# ── Interpolation ─────────────────────────────────────────────────────────────
interp       = RectBivariateSpline(eta_factors, cost_factors[::-1], LCOE[:, ::-1])
eta_fine     = np.linspace(eta_factors[0], eta_factors[-1], 300)
cost_fine    = np.linspace(cost_factors[-1], cost_factors[0], 300)
LCOE_fine    = interp(eta_fine, cost_fine)

# Convert axes to percentage for display
cost_red_fine = (1 - cost_fine) * 100      # 0 → 80 %
eta_imp_fine  = (eta_fine - 1) * 100       # 0 → 20 %

cost_red_grid, eta_imp_grid = np.meshgrid(cost_red_fine, eta_imp_fine)

# Reference point
LCOE_ref  = 60.68   # Steam Rankine
LCOE_curr = LCOE[0, 0]  # 81.27

# ── Plot ──────────────────────────────────────────────────────────────────────
fig, ax = plt.subplots(figsize=(14, 10))
ax.grid(False)

pcm = ax.pcolormesh(cost_red_grid, eta_imp_grid, LCOE_fine,
                    cmap='RdYlGn_r', shading='auto',
                    vmin=LCOE_fine.min(), vmax=LCOE_fine.max())

cbar = fig.colorbar(pcm, ax=ax, pad=0.02)
cbar.set_label(r'LCOE  [€ MWh$^{-1}$]', fontsize=24)
cbar.ax.tick_params(labelsize=20)

# Contour lines
contours = ax.contour(cost_red_grid, eta_imp_grid, LCOE_fine,
                      levels=10, colors='black', linewidths=0.8, alpha=0.4)
ax.clabel(contours, inline=True, fontsize=14, fmt='%.0f')

# Competitiveness isocurve
cs_ref = ax.contour(cost_red_grid, eta_imp_grid, LCOE_fine,
                    levels=[LCOE_ref], colors=['#2c5f7a'], linewidths=3, linestyles='--')
ax.clabel(cs_ref, fmt=f'{LCOE_ref:.1f}' + r' €$\,$MWh$^{-1}$', fontsize=20, inline=True)

ax.text(0.98, 0.98,
        f'Current: {LCOE[10, 0]:.1f}' + r'$\,$€$\,$MWh$^{-1}$',
        transform=ax.transAxes,
        fontsize=20,
        verticalalignment='top',
        horizontalalignment='right',
        bbox=dict(boxstyle='round,pad=0.4', facecolor='white',
                  edgecolor='#cccccc', linewidth=0.8, alpha=0.9))

ax.set_xlabel('Power block cost reduction (%)')
ax.set_ylabel(r'Net efficiency variation (%)')
ax.set_xlim(0, 80)
ax.set_ylim(-20, 20)
ax.xaxis.set_major_locator(ticker.MultipleLocator(10))
ax.yaxis.set_major_locator(ticker.MultipleLocator(4))
#ax.legend(loc='upper right', fontsize=20)

fig.tight_layout()
path = os.path.join(SAVE_DIR, "fig_sensitivity_salt_engine.pdf")
fig.savefig(path, bbox_inches='tight')
print(f"Saved → {path}")
plt.show()